/**
 * @summary Upload a file and create a proof record
 */
export const getUploadFileUrl = () => {
  return `/api/files/upload`;
};

export const uploadFile = async (
  uploadFileBody: UploadFileBody,
  options?: RequestInit,
): Promise<UploadResponse> => {
  const formData = new FormData();
  formData.append(`file`, uploadFileBody.file);
  formData.append(`title`, uploadFileBody.title);
  if (uploadFileBody.notes !== undefined && uploadFileBody.notes !== null) {
    formData.append(`notes`, uploadFileBody.notes);
  }
  if (
    uploadFileBody.projectId !== undefined &&
    uploadFileBody.projectId !== null
  ) {
    formData.append(`projectId`, uploadFileBody.projectId);
  }
  if (uploadFileBody.privacyMode !== undefined) {
    formData.append(`privacyMode`, uploadFileBody.privacyMode);
  }

  return customFetch<UploadResponse>(getUploadFileUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

