/**
 * @summary Get certificate verification data
 */
export const getVerifyCertificateUrl = (
  certificateId: string,
  params?: VerifyCertificateParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/verify/${certificateId}?${stringifiedParams}`
    : `/api/verify/${certificateId}`;
};

export const verifyCertificate = async (
  certificateId: string,
  params?: VerifyCertificateParams,
  options?: RequestInit,
): Promise<VerificationResponse> => {
  return customFetch<VerificationResponse>(
    getVerifyCertificateUrl(certificateId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getVerifyCertificateQueryKey = (
  certificateId: string,
  params?: VerifyCertificateParams,
) => {
  return [`/api/verify/${certificateId}`, ...(params ? [params] : [])] as const;
};

export const getVerifyCertificateQueryOptions = <
  TData = Awaited<ReturnType<typeof verifyCertificate>>,
  TError = ErrorType<ErrorResponse>,
>(
  certificateId: string,
  params?: VerifyCertificateParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof verifyCertificate>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ??
    getVerifyCertificateQueryKey(certificateId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof verifyCertificate>>
  > = ({ signal }) =>
    verifyCertificate(certificateId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!certificateId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof verifyCertificate>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

